const input = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const entryMode = $json.body && typeof $json.body === 'object' ? 'webhook' : (input.entry_mode || 'execute');
const normalize = (value) => String(value || '').trim();
const text = [input.title, input.objective, input.context, input.reason, input.summary, input.event_type, JSON.stringify(input.payload || input.normalized || {})].filter(Boolean).join(' ').toLowerCase();

const directory = [
  { name: 'Joel Bonilla', role: 'Cliente / Sponsor', tags: ['cliente','sponsor','stakeholder','aprobacion','aprobación','alcance','entrega','demo','cierre','manual','pdf','aceptacion','aceptación'], is_client: true },
  { name: 'David Manjarres', role: 'Backend / Tech Lead', tags: ['backend','api','postgres','db','database','servidor','infra','deploy','discord','n8n','bug','pr','merge','arquitectura','riesgo'], is_client: false },
  { name: 'David Josue Barragan', role: 'Frontend', tags: ['frontend','ui','ux','vercel','pantalla','dashboard','web','diseño','diseno','interfaz'], is_client: false },
  { name: 'Fernando Bonilla', role: 'QA / Documentacion', tags: ['qa','test','pruebas','pdf','reporte','documento','documentacion','documentación','manual','evidencia'], is_client: false },
  { name: 'Josue Garcia', role: 'QA / Integracion', tags: ['qa','integracion','integración','testing','validacion','validación','aceptacion','aceptación','trello'], is_client: false }
];

const selected = new Map();
const add = (person, reason) => {
  const key = normalize(person.name || person).toLowerCase();
  if (!key) return;
  selected.set(key, {
    name: person.name || person,
    role: person.role || 'Invitado',
    reason: reason || person.reason || 'Solicitado por contexto',
    email: person.email || null,
    discord_id: person.discord_id || null,
    is_client: Boolean(person.is_client)
  });
};

const explicit = Array.isArray(input.invitees) ? input.invitees : [];
explicit.forEach((p) => typeof p === 'string' ? add({ name: p }, 'Invitado explicitamente') : add(p, p.reason));
for (const person of directory) {
  const hit = person.tags.find((tag) => text.includes(tag));
  if (hit) add(person, `Contexto relacionado con ${hit}`);
}
if (/urgente|bloqueo|riesgo|release|entrega|aprobaci[oó]n|cliente|demo|cierre/.test(text)) {
  add(directory[0], 'Cliente/Sponsor requerido por impacto o aprobacion');
}
if (!selected.size) {
  add(directory[0], 'Sponsor por defecto para clasificar la reunion');
  add(directory[1], 'Tech Lead por defecto para resolver contexto tecnico');
}

const toLocalParts = (date = new Date()) => {
  const local = new Date(date.getTime() - 5 * 60 * 60 * 1000);
  return { y: local.getUTCFullYear(), m: local.getUTCMonth() + 1, d: local.getUTCDate(), h: local.getUTCHours(), min: local.getUTCMinutes(), dow: local.getUTCDay() };
};
const isoFromLocal = (y, m, d, h, min = 0) => new Date(Date.UTC(y, m - 1, d, h + 5, min, 0, 0)).toISOString();
const addDaysLocal = (parts, days) => {
  const dt = new Date(Date.UTC(parts.y, parts.m - 1, parts.d + days, 5, 0, 0));
  const local = new Date(dt.getTime() - 5 * 60 * 60 * 1000);
  return { y: local.getUTCFullYear(), m: local.getUTCMonth() + 1, d: local.getUTCDate(), h: 0, min: 0, dow: local.getUTCDay() };
};
const nextBusinessDay = (parts, offset = 1) => {
  let p = addDaysLocal(parts, offset);
  while (p.dow === 0 || p.dow === 6) p = addDaysLocal(p, 1);
  return p;
};
const roundHalfHour = (iso) => {
  const d = new Date(iso);
  const mins = d.getUTCMinutes();
  const add = mins === 0 ? 0 : mins <= 30 ? 30 - mins : 60 - mins;
  d.setUTCMinutes(mins + add, 0, 0);
  return d.toISOString();
};
const parsePreferred = () => {
  const raw = normalize(input.scheduled_for || input.preferred_time || input.when || input.fecha || input.context || input.title);
  if (input.scheduled_for || input.preferred_time || input.when || input.fecha) {
    const parsed = new Date(raw);
    if (!Number.isNaN(parsed.getTime())) return roundHalfHour(parsed.toISOString());
  }
  const now = new Date();
  const today = toLocalParts(now);
  let day = null;
  if (/pasado\s+ma[ñn]ana/.test(raw.toLowerCase())) day = nextBusinessDay(today, 2);
  else if (/ma[ñn]ana|tomorrow/.test(raw.toLowerCase())) day = nextBusinessDay(today, 1);
  else if (/hoy|today/.test(raw.toLowerCase())) day = today;
  const isoDate = raw.match(/(20\d{2})-(\d{1,2})-(\d{1,2})(?:[ tT]+(\d{1,2})(?::(\d{2}))?)?/);
  if (isoDate) {
    const h = Number(isoDate[4] || 10);
    const mi = Number(isoDate[5] || 0);
    return roundHalfHour(isoFromLocal(Number(isoDate[1]), Number(isoDate[2]), Number(isoDate[3]), h, mi));
  }
  const latamDate = raw.match(/(\d{1,2})[\/-](\d{1,2})[\/-](20\d{2})(?:\s+(\d{1,2})(?::(\d{2}))?)?/);
  if (latamDate) {
    const h = Number(latamDate[4] || 10);
    const mi = Number(latamDate[5] || 0);
    return roundHalfHour(isoFromLocal(Number(latamDate[3]), Number(latamDate[2]), Number(latamDate[1]), h, mi));
  }
  const time = raw.match(/\b(\d{1,2})(?::(\d{2}))?\s*(am|pm)?\b/i);
  if (day && time) {
    let h = Number(time[1]);
    const mi = Number(time[2] || 0);
    const mer = String(time[3] || '').toLowerCase();
    if (mer === 'pm' && h < 12) h += 12;
    if (mer === 'am' && h === 12) h = 0;
    return roundHalfHour(isoFromLocal(day.y, day.m, day.d, h, mi));
  }
  if (day) return roundHalfHour(isoFromLocal(day.y, day.m, day.d, 10, 0));
  const fallback = nextBusinessDay(today, 1);
  return roundHalfHour(isoFromLocal(fallback.y, fallback.m, fallback.d, 10, 0));
};

const durationRaw = Number.parseInt(input.duration_minutes || input.duration || (/demo|review|revisi[oó]n/.test(text) ? 45 : 30), 10);
const duration = Math.max(15, Math.min(120, Number.isFinite(durationRaw) ? durationRaw : 30));
const priority = ['low','medium','high','critical'].includes(String(input.priority || '').toLowerCase()) ? String(input.priority).toLowerCase() : (/bloqueo|critical|urgente|produccion|producción/.test(text) ? 'high' : 'medium');
const correlationId = input.correlation_id || input.event_id || `meeting-${Date.now()}`;
const title = normalize(input.title) || (priority === 'high' ? 'Reunion de desbloqueo PM' : 'Reunion de coordinacion PM');
const objective = normalize(input.objective || input.reason || input.summary) || 'Alinear contexto, responsables, siguientes acciones y riesgos.';
const contextSummary = normalize(input.context || input.input_summary || input.event_type || '') || 'Solicitud generada desde el bot PM.';
const idempotencyKey = input.idempotency_key || `meeting:${correlationId}:${title.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,'-').slice(0,48)}`;
const invitees = Array.from(selected.values());
const requestedFor = parsePreferred();

return [{ json: {
  entry_mode: entryMode,
  correlation_id: correlationId,
  source: input.source || 'bot',
  requested_by: input.requested_by || input.actor || input.usuario || 'pm_bot',
  title, objective, context_summary: contextSummary, priority,
  requested_for: requestedFor,
  duration_minutes: duration,
  status: input.status || 'scheduled',
  idempotency_key: idempotencyKey,
  invitees,
  timezone: 'America/Guayaquil',
  scheduling_policy: {
    working_days: 'Mon-Fri',
    windows: ['09:00-12:00', '14:00-17:30'],
    slot_minutes: 30,
    conflict_policy: 'no_overlapping_invitees'
  }
} }];

